# 리스트에서 특정 값 찾기
numbers = [12, 5, 33, 7, 18, 25]
target = 18

for i, num in enumerate(numbers):
    if num == target:
        print(f'{target}을 {i}번 인덱스에서 찾았습니다!')
        break
else:
    print(f'{target}을 찾지 못했습니다')
